// Parse backtest output
const output = $input.first().json;
const lines = output.stdout.split('\n');

let results = {
  pair: $json.pair,
  timeframe: $json.timeframe,
  status: 'completed',
  metrics: {}
};

lines.forEach(line => {
  if (line.includes('Win Rate:')) {
    results.metrics.win_rate = parseFloat(line.match(/([0-9.]+)%/)[1]);
  }
  if (line.includes('Total Trades:')) {
    results.metrics.total_trades = parseInt(line.match(/([0-9]+)/)[1]);
  }
  if (line.includes('Max Drawdown:')) {
    results.metrics.max_drawdown = parseFloat(line.match(/([0-9.]+)%/)[1]);
  }
  if (line.includes('Sharpe Ratio:')) {
    results.metrics.sharpe_ratio = parseFloat(line.match(/([0-9.]+)/)[1]);
  }
  if (line.includes('Final Equity:')) {
    results.metrics.final_equity = parseFloat(line.match(/([0-9.]+)/)[1]);
  }
  if (line.includes('Avg Win:')) {
    results.metrics.avg_win = parseFloat(line.match(/([0-9.]+)/)[1]);
  }
  if (line.includes('Avg Loss:')) {
    results.metrics.avg_loss = parseFloat(line.match(/([0-9.]+)/)[1]);
  }
});

return { ...results, execution_time: new Date().toISOString() };

