// Save results to JSON file for Performance Reporter
const fs = require('fs');
const path = require('path');

const resultsDir = '/sessions/busy-awesome-noether/mnt/forex_scalper_bot/backtest_results';
if (!fs.existsSync(resultsDir)) {
  fs.mkdirSync(resultsDir, { recursive: true });
}

const filename = path.join(resultsDir, `${$json.pair}_${$json.timeframe}_${Date.now()}.json`);
fs.writeFileSync(filename, JSON.stringify($json, null, 2));

return { saved_to: filename, status: 'success' };
